def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            base = (1 - ratio) ** 3
            score = base * 10
            for j in range(1, 5):
                val = (base ** j) * (j ** 2.5)
                if val > 7:
                    val /= (j * 1.5)
                if j % 3 == 0:
                    val *= 0.9
                else:
                    val *= 1.05
                score += val
            if int(capacity + item) % 6 == 0:
                score *= 0.92
            if score > 12:
                score = np.sqrt(score) * 2
        elif 0.2 <= ratio < 0.4:
            prod = 1
            limit = int(capacity // 3) + 2
            for n in range(1, limit):
                prod *= n + ratio
                if prod > 1e6:
                    prod %= 1234
            mod_factor = int(prod) % 600
            score += np.log1p(ratio * mod_factor) * 1.2
            if int(capacity) % 3 == 0 and abs((item * 4) % 1) < 1e-6:
                score += 4
            else:
                score -= 0.8
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x) % 1) ** 1.3 * (x ** 1.7)
            score += extra / 5
            if score > 15:
                score /= 1.5
        elif 0.4 <= ratio <= 0.65:
            for m in range(1, 6):
                incr = (ratio ** (m + 2)) * (m ** 4) / (m + 2)
                if m % 2 == 0:
                    incr *= 0.88
                else:
                    incr *= 1.12
                score += incr
            remain = capacity - item
            if remain < 3:
                score += 8 + remain * 1.2
            else:
                score -= remain * 0.6
            if score < 0:
                score = abs(score) * 0.27 + 0.8
            if int(capacity) % 7 == 0:
                score *= 1.15
            if (int(item * 5) % 4 == 0) and (int(capacity * 3) % 5 == 0):
                score += 2
        elif 0.65 < ratio <= 1.1:
            base_penalty = 0
            diff = ratio - 0.65
            for p in range(1, 10):
                fx = (diff ** p) * ((p ** 1.3) + 0.5)
                if p % 2 == 0:
                    fx *= 1.1
                else:
                    fx *= 0.95
                base_penalty += fx
            score = base_penalty * 12
            if capacity < item * 1.05:
                score += 13
            if (int(capacity * 15) % 7 == 0) and (int(item * 20) % 11 == 0):
                score -= 5
            if score < 0:
                score = score * -1.3 + 1.5
            if item % 0.1 == 0:
                score *= 1.07
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 11):
                val = ((diff) ** q) * (q ** 2.5)
                if q % 3 == 0:
                    val *= 0.93
                penalty += val
            score = penalty * 18
            if capacity < item * 1.7:
                score += 15
            if (int(capacity * 9) % 4 == 0) and (int(item * 13) % 3 == 0):
                score -= 6
            for z in range(3, 7):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.45
            if score > 800:
                score *= 0.85
        if capacity > 200:
            divisor = np.log1p(capacity) + np.sqrt(capacity/50)
            score /= divisor
        elif capacity < 5:
            score *= 2.1
        if abs(score) > 1200:
            score = np.sign(score) * 1200
        if score > 0 and (int(capacity) % 10 == 0):
            score *= 1.05
            if int(item*100) % 13 == 0:
                score += 3
        priorities[i] = score
    finite_p = priorities[np.isfinite(priorities)]
    if finite_p.size == 0:
        fill_val = 0
    else:
        q75 = np.percentile(finite_p, 75)
        count_top = np.sum(finite_p > q75)
        fill_val = np.max(finite_p) * (12 + count_top)
    priorities[np.isinf(priorities)] = fill_val
    med_p = np.median(finite_p) if finite_p.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = med_p
    return priorities
